slides.codeSnippet:
// ❌ Wrong: called conditionally
if (someCondition) {
  const [count, setCount] = useState(0);
}

// ❌ Wrong: called in a loop
for (let i = 0; i < 5; i++) {
  const [count, setCount] = useState(0);
}

// ❌ Wrong: called in a nested function
function handleClick() {
  const [count, setCount] = useState(0);
}

// ✅ Correct: always at top level
function MyComponent() {
  const [count, setCount] = useState(0);
  // ...
}
